INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, "青空の下で謁見", "ペコリーヌとの出会い", 40, 2, 20063115, 8, 2834, 5118061, "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", 7, 1, 0, "フリーマーケット会場", 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, "未来の騎空団\nマスコット？", "マホとの出会い", 40, 2, 20063115, 8, 2835, 5118062, "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", 7, 1, 0, "フリーマーケット会場", 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, "お嬢さまからの\n緊急依頼", "アキノとの出会い", 40, 2, 20063115, 8, 2837, 5118063, "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", 7, 1, 0, "ランドソル市街地", 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, "黄金色の悩みごと", "ジュンとの出会い", 40, 2, 20063115, 8, 4108402, 5118064, "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", 18, 1, 0, "フリーマーケット会場", 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, "白熱！　格闘大会！", "カオリとの出会い", 40, 2, 20063115, 8, 4107402, 5118065, "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", 18, 1, 0, "フリーマーケット会場", 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, "祭り太鼓はオーエドの華", "ニノンとの出会い", 40, 2, 20063115, 8, 9000227, 5118066, "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", 16, 1, 1, "オーエド町", 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, "人気者は遅れて\nやってくる", "スズナとの出会い", 40, 3, 20063115, 8, 2101181, 5118067, "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", 19, 1, 0, "フリーマーケット会場", 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, "巫女・ミーツ・魔法少女", "ナナカとの出会い", 40, 3, 20063115, 8, 4109402, 5118068, "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", 18, 1, 0, "ランドソル市街地", 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, "ネズ耳は二度なくなる", "キャル＆コッコロとの出会い", 40, 3, 20063115, 8, 4305402, 5118069, "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", 18, 1, 0, "フリーマーケット会場", 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, "この出会いにカンパイ！", "ユカリとの出会い", 40, 3, 20063115, 8, 4101402, 5118070, "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", 18, 1, 0, "ランドソル市街地", 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, "陰陽アンサンブル", "アオイとの出会い", 40, 3, 20063115, 8, 4106402, 5118071, "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", 18, 1, 0, "ランドソル市街地", 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, "運試し十番勝負！", "シノブとの出会い", 40, 3, 20063115, 8, 2836, 5118072, "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", 7, 1, 1, "フリーマーケット会場", 91002);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, "彼女たちの新たな日常", "オープニング", 0, 1, 20063115, 0, 0, 5118600, 0, 0, 0, 0, 0, 0);
